module.render:
const body = sections[0] ? sections[0].trim() : '';
const color = (args.color && String(args.color).trim()) || 'var(--accent-color)';
const variant = (args.variant || 'solid').toLowerCase();
const tc = (args.textcolor && String(args.textcolor).trim()) || '#ffffff';
const size = (args.size || 'md').toLowerCase();
let style;
if (variant === 'outline') {
  style = 'background-color: transparent; color: ' + color + '; border: 1.5px solid ' + color + ';';
} else if (variant === 'soft') {
  style = 'background-color: color-mix(in srgb, ' + color + ' 18%, transparent); color: ' + color + ';';
} else {
  style = 'background-color: ' + color + '; color: ' + tc + ';';
}
const cls = 'mdp-mod-badge mdp-badge-' + (['sm','md','lg'].indexOf(size) >= 0 ? size : 'md');
return '<span class="' + cls + '" style="' + style + '">' + body + '</span>';
